<?php
declare(strict_types=1);
putenv('APP_ENV=local'); require __DIR__.'/config.php';
$xlsx=$argv[1]??'C:\\Users\\Baysan\\Desktop\\vox2026.xlsx';if(!is_file($xlsx))exit("Excel bulunamadı.\n");$zip=new ZipArchive();if($zip->open($xlsx)!==true)exit("Excel açılamadı.\n");$shared=[];if(($xml=$zip->getFromName('xl/sharedStrings.xml'))!==false){$sx=simplexml_load_string($xml);foreach($sx->si as $si){$parts=[];if(isset($si->t))$parts[]=(string)$si->t;foreach($si->r as $run)$parts[]=(string)$run->t;$shared[]=implode('',$parts);}}
function refresh_2026_col(string $ref):int{preg_match('/^[A-Z]+/',$ref,$m);$n=0;foreach(str_split($m[0])as$ch)$n=$n*26+ord($ch)-64;return$n;}function refresh_2026_name(string $value):string{return mb_strtoupper(preg_replace('/\s+/u',' ',trim($value)),'UTF-8');}function refresh_2026_number(string $value,bool $phone=false):string{$value=trim($value);if($value===''||mb_strtoupper($value,'UTF-8')==='YOK')return$value;if(is_numeric($value))$value=sprintf('%.0f',(float)$value);$digits=preg_replace('/\D/','',$value);if($phone&&strlen($digits)===10)$digits='0'.$digits;return$digits?:$value;}
$patients=db()->query('SELECT id,full_name,record_date FROM patients')->fetchAll();$byYear=[];$byName=[];foreach($patients as $patient){$name=refresh_2026_name($patient['full_name']);$byYear[substr((string)$patient['record_date'],0,4).'|'.$name][]=$patient['id'];$byName[$name][]=$patient['id'];}$update=db()->prepare('UPDATE patients SET national_id=?,phone_primary=?,phone_secondary=? WHERE id=?');$sheet=simplexml_load_string($zip->getFromName('xl/worksheets/sheet1.xml'));$zip->close();$updated=0;$unmatched=[];
