echo "{$updated} hasta kaydının T.C. ve telefon bilgileri güncellendi. Eşleşmeyen: ".count($unmatched).".\n";if($unmatched)echo implode(PHP_EOL,array_slice($unmatched,0,20)).PHP_EOL;
